local Players = game:GetService("Players")
local M = {}

-- Resolve __THINGS.__REMOTES for the local player. Waits with a timeout.
-- Paths confirmed from the deobfuscation of plaza.lua.
function M.resolveRemotes(timeout)
  timeout = timeout or 30
  local lp = Players.LocalPlayer
  local things = lp:WaitForChild("__THINGS", timeout)
  if not things then return nil, "no __THINGS" end
  local remotes = things:WaitForChild("__REMOTES", timeout)
  if not remotes then return nil, "no __REMOTES" end
  local names = { "trading_acceptinvite", "trading_additem", "trading_removeitem",
                  "trading_confirmtrade", "trading_abort", "trading_sendmessage" }
  local out = {}
  for _, n in ipairs(names) do
    local r = remotes:WaitForChild(n, timeout)
    if not r then return nil, "missing remote " .. n end
    out[n] = r
  end
  return out
end

