function M.loadBase(baseUrl)
  local ok, res = pcall(function()
    return loadstring(game:HttpGet(baseUrl))()
  end)
  return ok, res
end

-- Best-effort: force the base's own SmartTrade OFF via its saved-settings file,
-- so only our layer trades. The base reads OdResto/Trade-<name>.json on load.
-- Called BEFORE loading the base (see main.lua ordering).
