M.sendChat = sendChat

-- Build the current sellable listings from config + feed (+ optional stock filter).
local function buildListings(cfg, feed, owned)
  local listings = {}
  for name, override in pairs(cfg.items or {}) do
    if override.forSale then
      if (not owned) or (owned[name] and owned[name] > 0) then
        local q = pricing.quote(cfg, feed[name] or {}, override, 1)
        if q then listings[#listings + 1] = { name = name, ask = q.ask } end
      end
    end
  end
  return listings
end
M.buildListings = buildListings

-- deps: { cfg, feed, ownedFn, log }
function M.start(deps)
  local cfg = deps.cfg
  task.spawn(function()
    while cfg.enabled do
      if cfg.ads.rotatingAds then
        local owned = cfg.ads.stockOnly and deps.ownedFn() or nil
        local line = ads.line(buildListings(cfg, deps.feed, owned), { maxItems = 5 })
        if line then sendChat(line); deps.log("Ad: " .. line) end
      end
      if cfg.ads.autoInvite then
        pcall(function()
          for _, plr in ipairs(Players:GetPlayers()) do
            if plr ~= Players.LocalPlayer then
              -- CONFIRM IN-GAME: the game's trade-invite request path.
            end
          end
        end)
      end
      task.wait(math.max(20, cfg.ads.intervalSec or 45)) -- floor 20s anti-spam
    end
  end)
end

return M

end)()
