-- === main ===
-- Universal Auto-Trade entry point. Loaded as one bundled script.
local CONFIG = {
  baseUrl = "https://raw.githubusercontent.com/0xfray/Mr-script/refs/heads/main/MR/plaza.lua",
  feedUrl = "https://raw.githubusercontent.com/0xfray/Mr-script/refs/heads/main/MR/value.lua",
  version = "v1.0",
}

local libConfig  = __M["lib.config"]
local libFeed    = __M["lib.feed"]
local libParse   = __M["lib.parse"]
local capmode    = __M["lib.capmode"]
local libStats   = __M["lib.stats"]
local LogBuf     = __M["lib.logbuf"]
local remotesM   = __M["runtime.remotes"]
local persist    = __M["runtime.persist"]
local inventory  = __M["runtime.inventory"]
local prober     = __M["runtime.prober"]
local TradeM     = __M["runtime.trade"]
local advertiser = __M["runtime.advertiser"]
local survival   = __M["runtime.survival"]
local webhookSend= __M["runtime.webhook_send"]
local cooldownLib= __M["lib.cooldown"]
local ui         = __M["runtime.ui"]

-- ---- logging -----------------------------------------------------------------
local dbg = LogBuf.new(500)
local function now() return string.format("%.2fs", os.clock()) end
local function logp(t) print("[AutoTrade] " .. t); dbg:info(t, now()) end
local function logstep(t) print("[AutoTrade] * " .. t); dbg:step(t, now()) end
local function logwarn(t) warn("[AutoTrade] " .. t); dbg:warn(t, now()) end
local function logok(t) print("[AutoTrade] OK " .. t); dbg:ok(t, now()) end

logstep("boot " .. CONFIG.version)

-- ---- 1) settings -------------------------------------------------------------
local cfg = libConfig.merge(libConfig.defaults(), persist.loadSettings() or {})
logok("settings loaded (enabled=" .. tostring(cfg.enabled) .. ")")

-- ---- 2) feed -----------------------------------------------------------------
local function fetchFeed()
  local ok, raw = pcall(function() return loadstring(game:HttpGet(CONFIG.feedUrl))() end)
  if ok and type(raw) == "table" then persist.saveFeedCache(raw); return libFeed.normalize(raw) end
  return nil, raw
end
local feed, feedErr = fetchFeed()
if feed then logok("feed fetched (" .. libFeed.count(feed) .. " items)")
else
  feed = libFeed.normalize(persist.loadFeedCache() or {})
  logwarn("feed fetch failed (" .. tostring(feedErr) .. "); cache=" .. libFeed.count(feed) .. " items")
end

-- ---- 3) stats + webhook ------------------------------------------------------
local statsObj = persist.loadStats() or libStats.new(os.time())
local function onEvent(event, data) pcall(webhookSend.send, cfg, event, data) end

-- ---- 4) debug report plumbing ------------------------------------------------
local function copyReport()
  local r = dbg:report("AutoTrade " .. CONFIG.version)
  local copied = false
  if setclipboard then copied = pcall(setclipboard, r)
  elseif toclipboard then copied = pcall(toclipboard, r) end
  print(r)
  return copied
end
local debugApi = {
  copy = copyReport,
  print = function() print(dbg:report("AutoTrade " .. CONFIG.version)) end,
}

-- ---- 5) build UI early (always appears) --------------------------------------
local uiHandle = ui.build({ cfg = cfg, feed = feed, save = persist.saveSettings,
                            stats = statsObj, debug = debugApi, onToggleEnabled = function() end })
if uiHandle then logok("WindUI panel loaded")
else logwarn("WindUI panel FAILED to load") end
local function setStatus(t) if uiHandle and uiHandle.setStatus then uiHandle.setStatus(t) end end

-- ---- 6) place guard: auto-trade only works in Trading Plaza ------------------
local wrongPlace = cfg.expectedPlaceId and game.PlaceId ~= cfg.expectedPlaceId
local remotes, rerr
if wrongPlace then
  logwarn(("WRONG GAME: place=%s. Auto-trade only works in Trading Plaza (%s). Teleport there and reload.")
    :format(tostring(game.PlaceId), tostring(cfg.expectedPlaceId)))
  setStatus("Wrong game. Open Trading Plaza (13200523806), then reload.")
  if uiHandle and uiHandle.notify then uiHandle.notify("Open Trading Plaza to trade - you're in the wrong game.") end
else
  setStatus("Loading base + remotes...")
  logstep("disabling base SmartTrade file")
  logok("disableBaseSmartTrade=" .. tostring(remotesM.disableBaseSmartTradeFile()))
  logstep("loading base plaza.lua")
  local baseOk = remotesM.loadBase(CONFIG.baseUrl)
  if baseOk then logok("base loaded") else logwarn("base FAILED to load") end

  logstep("resolving remotes")
  remotes, rerr = remotesM.resolveRemotes(30)
  if remotes then logok("remotes resolved (6/6)")
  else logwarn("remotes NOT resolved: " .. tostring(rerr)) end
end

-- ---- 8) probe the environment (this is what you send back) -------------------
logstep("probing environment")
pcall(function() prober.run(dbg, now()) end)
logok("probe complete")

-- ---- 9) survival (independent of remotes) ------------------------------------
survival.startAntiAfk(cfg)
survival.startReconnect(cfg, onEvent)
logok("survival started (antiAfk=" .. tostring(cfg.survival.antiAfk)
  .. " reconnect=" .. tostring(cfg.survival.autoReconnect) .. ")")

-- ---- 10) trading wiring (only when remotes resolved) -------------------------
if remotes then
  local chatState = {}
  pcall(function()
    local TextChatService = game:GetService("TextChatService")
    TextChatService:WaitForChild("TextChannels", 10):WaitForChild("RBXGeneral", 10)
    TextChatService.MessageReceived:Connect(function(msg)
      local who = msg.TextSource and msg.TextSource.Name
      local n = libParse.gems(msg.Text)
      if who and n then chatState[who] = n end
    end)
  end)
  local chat = {
    send = function(text) advertiser.sendChat(text) end,
    lastNumberFrom = function(name) return chatState[name] end,
  }

  local function getTradeState() return _G.__OdRestoTradeState end
  local function getGems() return tonumber(_G.__OdRestoGems) or 0 end

  local cooldownState = {}
  local function gate(name)
    local t = os.time()
    local okg = cooldownLib.allow(cfg, name, cooldownState[name], t)
    if okg then cooldownState[name] = t end
    return okg
  end

  local lastMode = "sell"
  local function mode()
    local gems = getGems()
    local m = capmode.mode(cfg, gems, lastMode)
    if m == "buy" and lastMode ~= "buy" then onEvent("cap", { gems = gems }); logp("gem cap -> buy mode") end
    lastMode = m
    return m
  end

  local function onSold(item, qty, gems, cost)
    libStats.recordSell(statsObj, gems, cost); persist.saveStats(statsObj)
    onEvent("sale", { item = item, qty = qty, gems = gems, profit = gems - cost })
    logp(("SOLD %s x%d for %s"):format(item, qty, tostring(gems)))
    setStatus(("Sold %s x%d for %s"):format(item, qty, tostring(gems)))
  end
  local function onBought(item, qty, gems)
    libStats.recordBuy(statsObj, gems); persist.saveStats(statsObj)
    onEvent("buy", { item = item, qty = qty, gems = gems })
    logp(("BOUGHT %s x%d for %s"):format(item, qty, tostring(gems)))
    setStatus(("Bought %s x%d for %s"):format(item, qty, tostring(gems)))
  end

  local runner = TradeM.new({
    remotes = remotes, cfg = cfg, feed = feed, chat = chat,
    getTradeState = getTradeState, log = logp,
    mode = mode, gate = gate, onSold = onSold, onBought = onBought,
  })
  survival.watchdog(cfg, "invite-loop", function()
    while true do
      if cfg.enabled then
        local st = getTradeState()
        if st and st.pendingInvite then runner:handleInvite() end
      end
      task.wait(1)
    end
  end, onEvent)

  advertiser.start({ cfg = cfg, feed = feed, ownedFn = inventory.owned, log = logp })
  setStatus("Ready. Trading " .. (cfg.enabled and "ENABLED" or "disabled") .. ".")
  logok("trading wired")
else
  setStatus("Remotes not found. UI only - press Copy Debug Report.")
end

-- ---- 11) periodic feed refresh -----------------------------------------------
if (cfg.feedRefreshSec or 0) > 0 then
  task.spawn(function()
    while true do
      task.wait(cfg.feedRefreshSec)
      local fresh = fetchFeed()
      if fresh then
        for k in pairs(feed) do feed[k] = nil end
        for k, v in pairs(fresh) do feed[k] = v end
        logp("feed refreshed (" .. libFeed.count(feed) .. " items)")
      end
    end
  end)
end

logstep("ready. items=" .. libFeed.count(feed) .. " remotes=" .. tostring(remotes ~= nil)
  .. " ui=" .. tostring(uiHandle ~= nil))
logp("Press 'Copy Debug Report' in the panel and send it back if anything looks off.")

